import type { ButtonHTMLAttributes, MouseEventHandler } from 'react';

import { cssModules } from '../../bpk-react-utils';

import { BpkStarNonRtl, type STAR_TYPES } from './BpkStar';

import STYLES from './BpkInteractiveStar.module.scss';

const getClassName = cssModules(STYLES);

type InteractiveStarType = typeof STAR_TYPES.EMPTY | typeof STAR_TYPES.FULL;

type NativeButtonProps = ButtonHTMLAttributes<HTMLButtonElement>;

export type Props = Omit<NativeButtonProps, 'className' | 'type' | 'onClick' | 'onMouseEnter' | 'name' | 'value' | 'aria-label' | 'aria-pressed'> & {
  label: string;
  name: string;
  onClick: MouseEventHandler<HTMLButtonElement>;
  onMouseEnter: MouseEventHandler<HTMLButtonElement>;
  type: InteractiveStarType;
  value: number;
  selected?: boolean;
  large?: boolean;
  extraLarge?: boolean;
};

const BpkInteractiveStar = ({
  label,
  name,
  onClick,
  onMouseEnter,
  selected = false,
  type,
  value,
  ...rest
}: Props) => {
  const buttonClassNames = getClassName(
    'bpk-interactive-star',
    selected && 'bpk-interactive-star--selected',
  );

  const iconClassNames = getClassName(
    'bpk-interactive-star__icon',
    selected && 'bpk-interactive-star__icon--selected',
  );

  // Note we use `BpkStarRatingNonRtl` here otherwise it already has `scaleX(-1)` applied in RTL.
  // That causes the scale animation to be a bit over the top.

  return (
    <button
      aria-label={label}
      onClick={onClick}
      onMouseEnter={onMouseEnter}
      className={buttonClassNames}
      aria-pressed={selected}
      type="button"
    >
      <div className={iconClassNames} >
        <BpkStarNonRtl
          type={type}
          {...rest}
        />
      </div>
    </button>
  );
};

export default BpkInteractiveStar;
